def smallest_Divisor(n: int) -> int:
    if n <= 1:
        return None  # No prime divisors for numbers <= 1
    if n % 2 == 0:
        return 2
    divisor = 3
    while divisor * divisor <= n:
        if n % divisor == 0:
            return divisor
        divisor += 2
    return n

