def find_rotation_count(arr):
    low, high = 0, len(arr) - 1
    n = len(arr)

    while low <= high:
        if arr[low] <= arr[high]:
            return low

        mid = (low + high) // 2
        next_idx = (mid + 1) % n
        prev_idx = (mid - 1 + n) % n

        if arr[mid] <= arr[next_idx] and arr[mid] <= arr[prev_idx]:
            return mid
        elif arr[mid] <= arr[high]:
            high = mid - 1
        else:
            low = mid + 1

    return 0

