def max_product(arr):
    if len(arr) < 2:
        return None  # Not enough elements for a pair

    # Initialize variables to track the two largest and two smallest numbers
    max1 = max2 = float('-inf')
    min1 = min2 = float('inf')

    for num in arr:
        # Update max1 and max2
        if num > max1:
            max2 = max1
            max1 = num
        elif num > max2:
            max2 = num

        # Update min1 and min2
        if num < min1:
            min2 = min1
            min1 = num
        elif num < min2:
            min2 = num

    # Compare product of two largest and two smallest numbers
    if max1 * max2 > min1 * min2:
        return (max2, max1)
    else:
        return (min2, min1)

