def is_majority(arr, n, x):
    # Since the array is sorted, we can use binary search to find the first occurrence of x
    def first_occurrence(arr, x):
        low, high = 0, len(arr) - 1
        result = -1
        while low <= high:
            mid = (low + high) // 2
            if arr[mid] == x:
                result = mid
                high = mid - 1
            elif arr[mid] < x:
                low = mid + 1
            else:
                high = mid - 1
        return result

    first_index = first_occurrence(arr, x)
    if first_index == -1:
        return False

    # Check if x occurs more than n/2 times
    if first_index + n // 2 < n and arr[first_index + n // 2] == x:
        return True
    return False

