def maximum_segments(n, a, b, c):
    # dp[i] will store the maximum number of segments for length i
    dp = [-1] * (n + 1)
    dp[0] = 0  # base case: 0 length means 0 segments

    for i in range(1, n + 1):
        for length in (a, b, c):
            if i - length >= 0 and dp[i - length] != -1:
                dp[i] = max(dp[i], dp[i - length] + 1)

    return dp[n]

