def max_sum(arr, n):
    # Calculate maximum sum increasing subsequence (MSIS) for each element
    msis = arr.copy()
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and msis[i] < msis[j] + arr[i]:
                msis[i] = msis[j] + arr[i]

    # Calculate maximum sum decreasing subsequence (MSDS) for each element
    msds = arr.copy()
    for i in range(n-2, -1, -1):
        for j in range(n-1, i, -1):
            if arr[i] > arr[j] and msds[i] < msds[j] + arr[i]:
                msds[i] = msds[j] + arr[i]

    # Find maximum sum of bitonic subsequence by combining MSIS and MSDS
    max_sum_bitonic = 0
    for i in range(n):
        # Subtract arr[i] because it is counted twice in msis[i] + msds[i]
        current_sum = msis[i] + msds[i] - arr[i]
        if current_sum > max_sum_bitonic:
            max_sum_bitonic = current_sum

    return max_sum_bitonic

# Verification of the assertions
assert max_sum([1, 15, 51, 45, 33, 100, 12, 18, 9], 9) == 194
assert max_sum([80, 60, 30, 40, 20, 10], 6) == 210
assert max_sum([2, 3 ,14, 16, 21, 23, 29, 30], 8) == 138

