def lcm(a, b):
    # To find LCM, we use the formula: LCM(a,b) = abs(a*b) // GCD(a,b)
    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x
    return abs(a * b) // gcd(a, b)

