def find_peak(arr, n):
    # A peak element is an element that is greater than its neighbors.
    # For corner elements, we need to check only one neighbor.
    for i in range(n):
        if i == 0:
            if n == 1 or arr[i] >= arr[i + 1]:
                return i
        elif i == n - 1:
            if arr[i] >= arr[i - 1]:
                return i
        else:
            if arr[i] >= arr[i - 1] and arr[i] >= arr[i + 1]:
                return i
    return -1  # If no peak is found, though problem constraints imply there is always a peak.

