def Sum(n):
    def is_prime(x):
        if x < 2:
            return False
        for i in range(2, int(x**0.5) + 1):
            if x % i == 0:
                return False
        return True

    prime_divisors = set()
    # Check for 2 separately to allow increment by 2 later
    while n % 2 == 0:
        prime_divisors.add(2)
        n //= 2

    # Check for odd factors
    for i in range(3, int(n**0.5) + 1, 2):
        while n % i == 0:
            if is_prime(i):
                prime_divisors.add(i)
            n //= i

    # If n is still > 2, then it is prime
    if n > 2:
        prime_divisors.add(n)

    return sum(prime_divisors)

# Verification of the assertions
assert Sum(60) == 10
assert Sum(39) == 16
assert Sum(40) == 7

