def get_pairs_count(arr, n, k):
    count = 0
    freq = {}
    for num in arr:
        freq[num] = freq.get(num, 0) + 1
    for num in arr:
        count += freq.get(k - num, 0)
        if k - num == num:
            count -= 1
    return count // 2

