def find_kth(arr1, arr2, n, m, k):
    # Use two pointers to traverse both arrays
    i = 0
    j = 0
    count = 0
    while i < n and j < m:
        if arr1[i] < arr2[j]:
            count += 1
            if count == k:
                return arr1[i]
            i += 1
        else:
            count += 1
            if count == k:
                return arr2[j]
            j += 1
    # If elements left in arr1
    while i < n:
        count += 1
        if count == k:
            return arr1[i]
        i += 1
    # If elements left in arr2
    while j < m:
        count += 1
        if count == k:
            return arr2[j]
        j += 1

# Verification of the assertions
