def min_coins(coins, m, V):
    # Initialize DP array with a large number (infinity substitute)
    dp = [float('inf')] * (V + 1)
    dp[0] = 0  # Base case: 0 coins needed to make value 0

    for i in range(1, V + 1):
        for j in range(m):
            if coins[j] <= i:
                sub_res = dp[i - coins[j]]
                if sub_res != float('inf') and sub_res + 1 < dp[i]:
                    dp[i] = sub_res + 1

    return dp[V] if dp[V] != float('inf') else -1

