def get_median(arr1, arr2, n):
    # Helper function to find median of a single sorted array
    def median_single(arr, n):
        if n % 2 == 0:
            return (arr[n//2] + arr[n//2 - 1]) / 2
        else:
            return arr[n//2]

    # Base cases
    if n == 0:
        return -1  # Undefined for empty arrays
    if n == 1:
        return (arr1[0] + arr2[0]) / 2
    if n == 2:
        return (max(arr1[0], arr2[0]) + min(arr1[1], arr2[1])) / 2

    m1 = median_single(arr1, n)
    m2 = median_single(arr2, n)

    if m1 == m2:
        return m1

    # if m1 < m2, then median must exist in arr1[m1....] and arr2[....m2]
    if m1 < m2:
        if n % 2 == 0:
            return get_median(arr1[n//2:], arr2[:n//2], n - n//2)
        else:
            return get_median(arr1[n//2:], arr2[:n//2+1], n - n//2)
    else:
        if n % 2 == 0:
            return get_median(arr1[:n//2], arr2[n//2:], n - n//2)
        else:
            return get_median(arr1[:n//2+1], arr2[n//2:], n - n//2)

