def find_triplet_array(arr, n, sum_val):
    arr.sort()
    for i in range(n - 2):
        left = i + 1
        right = n - 1
        while left < right:
            current_sum = arr[i] + arr[left] + arr[right]
            if current_sum == sum_val:
                return (arr[i], arr[left], arr[right])
            elif current_sum < sum_val:
                left += 1
            else:
                right -= 1
    return None

