def nCr_mod_p(n, r, p):
    # Function to compute x^y mod p using binary exponentiation
    def mod_exp(x, y, p):
        result = 1
        x = x % p
        while y > 0:
            if y & 1:
                result = (result * x) % p
            y = y >> 1
            x = (x * x) % p
        return result

    # Function to compute modular inverse of a under modulo p
    # using Fermat's little theorem, p must be prime
    def mod_inv(a, p):
        return mod_exp(a, p - 2, p)

    if r > n:
        return 0
    if r == 0 or r == n:
        return 1

    # Compute factorials mod p
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = (fact[i - 1] * i) % p

    # nCr mod p = fact[n] * mod_inv(fact[r], p) * mod_inv(fact[n-r], p) mod p
    return (fact[n] * mod_inv(fact[r], p) * mod_inv(fact[n - r], p)) % p


