def super_seq(str1, str2, m, n):
    # Create a DP table to store lengths of longest common subsequence of substrings
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Fill dp table
    for i in range(m + 1):
        for j in range(n + 1):
            if i == 0 or j == 0:
                dp[i][j] = 0
            elif str1[i - 1] == str2[j - 1]:
                dp[i][j] = 1 + dp[i - 1][j - 1]
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Length of shortest supersequence is sum of input strings lengths minus length of LCS
    return m + n - dp[m][n]

