def pancake_sort(arr):
    def flip(sub_arr, k):
        sub_arr[:k] = sub_arr[:k][::-1]

    n = len(arr)
    for size in range(n, 1, -1):
        max_idx = arr.index(max(arr[:size]))
        if max_idx != size - 1:
            if max_idx != 0:
                flip(arr, max_idx + 1)
            flip(arr, size)
    return arr

