def solution(a, b, n):
    # Extended Euclidean Algorithm to find x, y such that ax + by = gcd(a, b)
    def extended_gcd(aa, bb):
        if bb == 0:
            return (aa, 1, 0)
        gcd, x1, y1 = extended_gcd(bb, aa % bb)
        x = y1
        y = x1 - (aa // bb) * y1
        return (gcd, x, y)

    gcd, x, y = extended_gcd(a, b)
    if n % gcd != 0:
        return 'No solution'
    # Scale the solution to n
    x *= n // gcd
    y *= n // gcd
    return ('x = ', x, ', y = ', y)

