def magic_square_test(square):
    n = len(square)
    # Check if all rows have the same length as n
    if any(len(row) != n for row in square):
        return False

    # Calculate the sum of the first row as the target sum
    target_sum = sum(square[0])

    # Check sums of all rows
    for row in square:
        if sum(row) != target_sum:
            return False

    # Check sums of all columns
    for col in range(n):
        if sum(square[row][col] for row in range(n)) != target_sum:
            return False

    # Check sum of main diagonal
    if sum(square[i][i] for i in range(n)) != target_sum:
        return False

    # Check sum of secondary diagonal
    if sum(square[i][n - 1 - i] for i in range(n)) != target_sum:
        return False

    return True

