def fibonacci(n):
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        return fibonacci(n-1) + fibonacci(n-2)

# Verification of the assertions
assert fibonacci(7) == 13
assert fibonacci(8) == 21
assert fibonacci(9) == 34

def check_subset(t1, t2):
