def find_Max(arr, low, high):
    # If the array is not rotated at all
    if high < low:
        return arr[high]
    # If there is only one element left
    if high == low:
        return arr[low]

    mid = (low + high) // 2

    # Check if mid itself is maximum
    if mid < high and arr[mid] > arr[mid + 1]:
        return arr[mid]
    # Check if mid-1 is maximum
    if mid > low and arr[mid] < arr[mid - 1]:
        return arr[mid - 1]

    # Decide whether to go to left half or right half
    if arr[low] >= arr[mid]:
        return find_Max(arr, low, mid - 1)
    return find_Max(arr, mid + 1, high)

# Verification of the function with the provided assertions
try:
    assert find_Max([2,3,5,6,9],0,4) == 9
    assert find_Max([3,4,5,2,1],0,4) == 5
    assert find_Max([1,2,3],0,2) == 3
    verification_result = "All assertions passed."
except AssertionError:
    verification_result = "One or more assertions failed."

verification_result

